INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00633', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「平頷鱲是臺灣引進日本發眼香魚卵放流時所誤進的外來魚種，主要見於河川中下游，可忍受較輕度 污染的溪段環境，性喜愛跳躍，具群居性，繁殖期會在淺瀨、平瀨處的小石礫中產卵，此段期間具有 領域性。屬雜食性魚類，以水生昆蟲、小蝦、落水昆蟲、植物碎屑物、浮游生物、藻類為食，由於跳 躍力佳，晨昏時會捕食蜉蝣以及飛蚊。」 根據上文，下列對平頷鱲的描述何者正確？', '["是稀有魚種、來自日本的香魚，會溯溪捕獵", "不計葷素，擅長跳水獵殺，會狙擊大型生物", "有較高的環境適應力，喜歡成群結隊的活動", "具跳躍能力的魚類，體力佳，適合長途競泳 食物來源多元化，選擇水流淺急的瀨處產卵"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00634', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「所謂的『醫學』從來不只是客觀理性的醫學問題，而必然是『人』的問題。根據北宋學者沈括的記 敘，他很可能觀察到了類似於今日的漸凍人症等當時罕見而令人感到困惑的病症，只是那時他並不知 道致病的原因以及如何治療；但沈括還是細膩地記載各項病理症狀，其初衷來自於『終以此不幸，無 人識其疾，每為之哀傷』的同理心，正是這樣的素養，使得醫學與人文得以交融，那避免了當代哲學 與醫學老死不相往來所造成治療過程中的倫理問題及病患的痛苦。」 根據上文，下列選項何者符合作者之論點？', '["沒有人文涉入的醫學可能造成病患不被理解的痛苦", "沈括的思維符合當代傳統普遍認知的「醫學」定義", "人文精神可以避免醫學落入過於客觀與理性的思維中", "北宋時期已經普遍知曉漸凍人症，只是當時無有其名 沈括詳載不知名病症，期望能找到致病與治療的因子"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00635', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「最會做考卷選擇題的人，可能最不會做人生選擇。人生是無數選擇的總集合，每個選擇都沒有標準 答案，適合他人的路不見得適合你。有人選最多人走的那條平穩之路，有人則選擇人跡較少之路。錯 誤的選擇會帶來痛苦，但有時痛苦並非來自選擇錯誤而是欠缺機運以致留下遺憾。即使如此，我們也 不能不慎重做出選擇，因為如果我們不在乎那珍貴的選擇權，很快地，我們將變成被選擇的人。」 根據上文，下列選項敘述正確的是：', '["即使做出完全正確的選擇，也可能留下遺憾", "選擇人跡罕至之路的人，往往比較容易成功", "機運比選擇重要，欠缺機運的人不可能成功", "我們若不在乎選擇權，就可能變得無可選擇 選擇與個人特質有關，結果是否理想因人而異"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00636', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「臺灣已進入高齡化社會，面對社會、經濟、政治及家庭結構動盪轉變時，老人在生理及心理上都比 較不易調適。因此我們更需要重視老人在憂鬱症的生物學因素及社會心理因素互動下所呈現的憂鬱 症，既不偏重社會心理層面的影響，也不忽略生物學因素對憂鬱症之診斷及治療的重要性。提供適合 臺灣本土的治療體系，使老人憂鬱症獲得妥當的照顧。」 根據上文，下列選項正確的是：', '["藉由改善生活環境及家庭關懷，可以緩解老人憂鬱症的發生", "隨著年歲的增加，老人更容易因身心調適不良而罹患憂鬱症", "有效控制老人憂鬱症的方法，應當積極引進西方的治療體系", "照顧老人憂鬱症患者，須同時兼顧生物學與心理層面的因素 建立良好社會互動機制，可讓憂鬱症患者獲得更妥善的照顧"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00637', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「當SARS來襲，人們戴上口罩，抵擋飛沫，甚至連戀人都不敢貿然交換唾沫。然而，本質與飛沫相 近的流言，我們卻不曾稍加阻攔，任憑浮誇的、未加證實的言辭氾濫，傷及無辜。事實上，流言比飛 沫更易促人衰竭。因此，唾液並不可怕，我們該關心的是如何不再繼續生產並防堵這些虛妄言論。」 根據上文，下列選項何者符合文意？', '["不實言論傷害人更甚於病毒", "人言可畏流言應該止於智者", "人們從疾病恐懼中獲得成長", "遏止疾病和謠言需防患未然 杜絕流言比殺死病毒更困難"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00638', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲起訴主張其與乙（住所地為A地）、丙（住所地為B地），三人在C地簽立借款契約書，約定由乙 向甲借款新臺幣（下同）100萬元，並以丙為該借款連帶保證人，且自交付借款之日起6個月內，應 至D地（甲之住所地）如數返還借款予甲，甲於簽約時一併如數交付借款予乙，惟乙屆期仍不清償等 情，爰依消費借貸及連帶保證法律關係，請求乙及丙連帶返還借款100萬元。有關本件訴訟管轄，下 列敘述何者正確？', '["本件訴訟因乙及丙住所地依序為A地及B地，各該被告之住所地法院即A地及B地之法院均有管 轄權", "本件訴訟因乙為主債務人，乙住所地A地之法院始有管轄權", "本件訴訟因借款契約書簽立地點為C地，C地之法院始有管轄權", "本件訴訟因借款契約書約定以甲住所地為清償地，D地之法院始有管轄權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00639', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於合意管轄，下列敘述何者正確？', '["如無特殊約定，合意管轄應解為排他的合意管轄", "經當事人合意之管轄法院，即為專屬管轄法院", "為便利訴訟，當事人得以合意約定第二審管轄法院", "民事訴訟法第25條之擬制管轄，不適用在兩造有排他合意管轄約定之情形"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00640', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者，不得為無訴訟能力人聲請受訴法院選任特別代理人？', '["對無訴訟能力人為訴訟行為者", "無訴訟能力人之親屬", "無訴訟能力人之利害關係人", "檢察官"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00641', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者不具備民事訴訟之當事人能力？', '["甲獨資商號，因販賣傳統生活用品雜貨而涉訟", "胎兒甲，因繼承權受侵害，而有提起訴訟之必要", "甲分公司，就其業務範圍之事項涉訟", "甲法人，因其代表人執行職務之侵權行為涉訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00642', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲委任乙律師為訴訟代理人，對被告丙提起訴訟，下列何種訴訟行為，乙必須受特別委任方得為之？', '["聲明證據", "丙提起反訴時，對該反訴為言詞辯論", "為甲提起上訴", "聲請假扣押"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
